using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(Uri = "config://app/settings", Name = "App Settings",
        Description = "Returns the current application configuration")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "production",
            Version = "1.2.0",
            Features = new { DarkMode = true, BetaAccess = false },
            MaxConnections = 100
        };
        return System.Text.Json.JsonSerializer.Serialize(config,
            new System.Text.Json.JsonSerializerOptions { WriteIndented = true });
    }
}

using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer;

[McpServerToolType]
public static class Tools
{
    [McpServerTool(Name = "echo"), Description("Echoes back the provided message")]
    public static string Echo([Description("The message to echo")] string message)
    {
        return $"Echo: {message}";
    }

    [McpServerTool(Name = "get_time"), Description("Returns the current server time")]
    public static string GetTime()
    {
        return DateTime.UtcNow.ToString("o");
    }
}

